UPDATE docs SET title = 'Core Values', description = 'The bedrock principles of ARES 23247.', content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"ARES 23247 Core Values"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"The Mountaineer Mindset"}]},{"type":"paragraph","content":[{"type":"text","text":"Grit, Determination, and Innovation are the pillars of the ARES 23247 mindset. We do not stop when things get hard."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Gracious Professionalism"}]},{"type":"paragraph","content":[{"type":"text","text":"We compete fiercely, but treat everyone with respect and kindness."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Relentless Improvement"}]},{"type":"paragraph","content":[{"type":"text","text":"We evaluate every system, every codebase, and every CAD model to ensure championship-grade reliability."}]},{"type":"interactiveComponent","attrs":{"componentName":"CoreValueCallout"}}]}' WHERE slug = 'culture-core-values';
UPDATE docs SET title = 'Code Challenges', description = 'Test your knowledge with interactive Code Challenges.', content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Interactive Code Challenges"}]},{"type":"paragraph","content":[{"type":"text","text":"Take our automated code challenges and improve your programming skills."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Challenge 1: The NaN Firewall"}]},{"type":"paragraph","content":[{"type":"text","text":"Implement a safe arithmetic operation that ensures no NaN propagates."}]},{"type":"interactiveComponent","attrs":{"componentName":"CodePlayground"}}]}' WHERE slug = 'interactive-code-challenges';
UPDATE docs SET title = 'Java Basics Quiz', description = 'Quiz yourself on Java programming fundamentals.', content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Java Basics Quiz"}]},{"type":"paragraph","content":[{"type":"text","text":"The Java basics quiz tests your knowledge on data types, loops, and object oriented programming."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Instructions"}]},{"type":"paragraph","content":[{"type":"text","text":"Use the interactive quiz module below."}]},{"type":"interactiveComponent","attrs":{"componentName":"InteractiveTutorial"}}]}' WHERE slug = 'interactive-java-basics-quiz';
UPDATE docs SET title = 'Interactive Code Playground', description = 'Sandbox for exploring ARESLib utilities.', content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Interactive Code Playground"}]},{"type":"paragraph","content":[{"type":"text","text":"A sandbox environment for running simulated FTC robot code right from the documentation portal."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Try it out"}]},{"type":"paragraph","content":[{"type":"text","text":"Explore the various classes and methods below."}]},{"type":"interactiveComponent","attrs":{"componentName":"CodePlayground"}}]}' WHERE slug = 'interactive-code-playground';
UPDATE docs SET title = 'Hardware Bus Troubleshooting', description = 'How to diagnose and fix I2C / CAN bus dropouts.', content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Hardware Bus Troubleshooting"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Identifying the Issue"}]},{"type":"paragraph","content":[{"type":"text","text":"If your robot stops responding and REV hardware reports communication failures, you may have a bus dropout."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Resolution Steps"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Check your wiring for loose crimps or exposed copper."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Ensure loop times are constrained to 20ms."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Use the AresAlert dashboard to isolate failing nodes."}]},{"type":"interactiveComponent","attrs":{"componentName":"FaultSim"}}]}' WHERE slug = 'troubleshooting-hardware-bus';
UPDATE docs SET title = 'Network Issues', description = 'Troubleshooting Control Hub Wi-Fi and connection issues.', content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Network Issues"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Diagnosing Dropouts"}]},{"type":"paragraph","content":[{"type":"text","text":"A robust 5GHz connection is required for continuous telemetry streams."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Solutions"}]},{"type":"paragraph","content":[{"type":"text","text":"- Avoid using Bluetooth devices near the driver station."}]},{"type":"paragraph","content":[{"type":"text","text":"- Ensure your client device is connected to the 5GHz FTC network."}]},{"type":"paragraph","content":[{"type":"text","text":"- Update Control Hub firmware."}]},{"type":"interactiveComponent","attrs":{"componentName":"TroubleshootingWizard"}}]}' WHERE slug = 'troubleshooting-network-issues';
UPDATE docs SET title = 'Robot Won''t Move', description = 'Checklist to follow when the drivetrain is unresponsive.', content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Robot Won''t Move"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Initial Checks"}]},{"type":"paragraph","content":[{"type":"text","text":"Ensure the battery is above 12.5V and securely plugged in. Check the driver station for active faults."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Deep Dive"}]},{"type":"paragraph","content":[{"type":"text","text":"If the robot still refuses to move, check for firmware mismatch on the Expansion Hub or verify that the active OpMode doesn''t have a failing assertion."}]},{"type":"interactiveComponent","attrs":{"componentName":"PowerSheddingSim"}},{"type":"interactiveComponent","attrs":{"componentName":"TroubleshootingWizard"}}]}' WHERE slug = 'troubleshooting-robot-wont-move';
UPDATE docs SET title = 'Operations Checklist', description = 'Pre-flight checklist for competition matches.', content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Operations Checklist"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Pre-Match Checks"}]},{"type":"paragraph","content":[{"type":"text","text":"The following items must be verified before the robot is placed on the field:"}]},{"type":"paragraph","content":[{"type":"text","text":"- Battery > 13.0V"}]},{"type":"paragraph","content":[{"type":"text","text":"- All Anderson connectors verified secure."}]},{"type":"paragraph","content":[{"type":"text","text":"- Camera lenses clean."}]},{"type":"paragraph","content":[{"type":"text","text":"- Drive train modules straight."}]}]}' WHERE slug = 'operations-checklist';
